// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import {Ownable} from "@openzeppelin/contracts/access/Ownable.sol";

contract HBReferralRegistry is Ownable {
    mapping(address => address) public sponsorOf;
    mapping(bytes32 => address) public referralCodeOwner;
    mapping(address => bytes32) public referralCodeOf;

    event ReferralCodeRegistered(address indexed user, bytes32 indexed referralCode);
    event SponsorLinked(address indexed user, address indexed sponsor, bytes32 indexed referralCode);

    constructor(address initialOwner) Ownable(initialOwner) {}

    function registerCode(bytes32 referralCode) external {
        require(referralCode != bytes32(0), "HB: empty code");
        require(referralCodeOwner[referralCode] == address(0), "HB: code used");
        require(referralCodeOf[msg.sender] == bytes32(0), "HB: user has code");
        referralCodeOwner[referralCode] = msg.sender;
        referralCodeOf[msg.sender] = referralCode;
        emit ReferralCodeRegistered(msg.sender, referralCode);
    }

    function linkSponsor(address user, address sponsor, bytes32 referralCode) external onlyOwner {
        require(user != address(0), "HB: user zero");
        require(sponsor != address(0), "HB: sponsor zero");
        require(user != sponsor, "HB: self sponsor");
        require(sponsorOf[user] == address(0), "HB: sponsor locked");
        sponsorOf[user] = sponsor;
        emit SponsorLinked(user, sponsor, referralCode);
    }
}

contracts/HBTreasurySplitter.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import {IERC20} from "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import {SafeERC20} from "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import {Ownable} from "@openzeppelin/contracts/access/Ownable.sol";
import {Ownable2Step} from "@openzeppelin/contracts/access/Ownable2Step.sol";
import {Pausable} from "@openzeppelin/contracts/utils/Pausable.sol";
import {ReentrancyGuard} from "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

contract HBTreasurySplitter is Ownable2Step, Pausable, ReentrancyGuard {
    using SafeERC20 for IERC20;

    IERC20 public immutable paymentToken;

    address public directIncomeTreasury;
    address public productAllocationTreasury;
    address public rechargeTreasury;
    address public levelIncomeTreasury;
    address public singleLegTreasury;
    address public companyReserveTreasury;

    event TreasuryUpdated(bytes32 indexed key, address indexed wallet);
    event DistributionCreated(
        bytes32 indexed purchaseId,
        address indexed buyer,
        uint256 amount,
        uint256 directAmount,
        uint256 productAmount,
        uint256 rechargeAmount,
        uint256 levelAmount,
        uint256 singleLegAmount,
        uint256 companyReserveAmount
    );

    constructor(IERC20 token, address initialOwner) Ownable(initialOwner) {
        require(address(token) != address(0), "HB: token zero");
        paymentToken = token;
    }

    function setTreasuries(
        address directWallet,
        address productWallet,
        address rechargeWallet,
        address levelWallet,
        address singleLegWallet,
        address companyWallet
    ) external onlyOwner {
        _requireWallet(directWallet);
        _requireWallet(productWallet);
        _requireWallet(rechargeWallet);
        _requireWallet(levelWallet);
        _requireWallet(singleLegWallet);
        _requireWallet(companyWallet);
        directIncomeTreasury = directWallet;
        productAllocationTreasury = productWallet;
        rechargeTreasury = rechargeWallet;
        levelIncomeTreasury = levelWallet;
        singleLegTreasury = singleLegWallet;
        companyReserveTreasury = companyWallet;
        emit TreasuryUpdated("direct", directWallet);
        emit TreasuryUpdated("product", productWallet);
        emit TreasuryUpdated("recharge", rechargeWallet);
        emit TreasuryUpdated("level", levelWallet);
        emit TreasuryUpdated("single_leg", singleLegWallet);
        emit TreasuryUpdated("company", companyWallet);
    }

    function split(bytes32 purchaseId, address buyer, uint256 amount) external onlyOwner nonReentrant whenNotPaused {
        _requireConfigured();
        uint256 directAmount = (amount * 15) / 100;
        uint256 productAmount = (amount * 30) / 100;
        uint256 rechargeAmount = (amount * 30) / 100;
        uint256 levelAmount = (amount * 10) / 100;
        uint256 singleLegAmount = (amount * 15) / 100;
        uint256 allocated = directAmount + productAmount + rechargeAmount + levelAmount + singleLegAmount;
        uint256 companyAmount = amount - allocated;

        paymentToken.safeTransfer(directIncomeTreasury, directAmount);
        paymentToken.safeTransfer(productAllocationTreasury, productAmount);
        paymentToken.safeTransfer(rechargeTreasury, rechargeAmount);
        paymentToken.safeTransfer(levelIncomeTreasury, levelAmount);
        paymentToken.safeTransfer(singleLegTreasury, singleLegAmount);
        if (companyAmount > 0) paymentToken.safeTransfer(companyReserveTreasury, companyAmount);

        emit DistributionCreated(purchaseId, buyer, amount, directAmount, productAmount, rechargeAmount, levelAmount, singleLegAmount, companyAmount);
    }

    function pause() external onlyOwner {
        _pause();
    }

    function unpause() external onlyOwner {
        _unpause();
    }

    function _requireConfigured() internal view {
        _requireWallet(directIncomeTreasury);
        _requireWallet(productAllocationTreasury);
        _requireWallet(rechargeTreasury);
        _requireWallet(levelIncomeTreasury);
        _requireWallet(singleLegTreasury);
        _requireWallet(companyReserveTreasury);
    }

    function _requireWallet(address wallet) internal pure {
        require(wallet != address(0), "HB: treasury zero");
    }
}

